---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"aside"> &
  VariantProps<typeof variants> & {
    storageKey?: string
  }

const variants = cva("relative flex items-center py-2", {
  variants: {
    variant: {
      default: "bg-foreground text-background w-full",
      floating:
        "bg-background mx-auto my-2 w-[calc(100%-2rem)] max-w-[calc(var(--container,1280px)-2rem)] overflow-hidden rounded-lg border shadow-sm",
    },
  },
  defaultVariants: {
    variant: "default",
  },
})

const { class: className, variant, storageKey, ...props } = Astro.props
---

<aside
  class={cn(variants({ variant }), className)}
  data-slot="banner"
  data-banner-storage-key={storageKey}
  data-variant={variant}
  {...props}
>
  <slot />
</aside>

<script is:inline>
  const initializedKey = "fulldevBannerInitialized"

  if (!document.documentElement.dataset[initializedKey]) {
    document.documentElement.dataset[initializedKey] = "true"

    const getStorageToken = (key) => `banner:${key}`

    const syncBanners = () => {
      document.querySelectorAll("[data-slot='banner']").forEach((banner) => {
        if (!(banner instanceof HTMLElement)) return

        const storageKey = banner.dataset.bannerStorageKey

        if (
          storageKey &&
          sessionStorage.getItem(getStorageToken(storageKey)) === "hidden"
        ) {
          banner.hidden = true
        }
      })
    }

    syncBanners()

    document.addEventListener("click", (event) => {
      const target = event.target

      if (!(target instanceof Element)) return

      const closeButton = target.closest("[data-slot='banner-close']")

      if (!(closeButton instanceof HTMLElement)) return

      const banner = closeButton.closest("[data-slot='banner']")

      if (!(banner instanceof HTMLElement)) return

      banner.hidden = true

      const storageKey = banner.dataset.bannerStorageKey

      if (storageKey) {
        sessionStorage.setItem(getStorageToken(storageKey), "hidden")
      }
    })
  }
</script>
